const fs = require('fs');

const filePath = process.argv[2];
if (!filePath) {
  process.stderr.write('Usage: node extract.js <elf-file>\n');
  process.exit(1);
}

const buf = fs.readFileSync(filePath);

// Verify ELF magic
if (buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('Not an ELF file\n');
  process.exit(1);
}

const is64 = buf[4] === 2;
const isLE = buf[5] === 1;

function readU16(offset) {
  return isLE ? buf.readUInt16LE(offset) : buf.readUInt16BE(offset);
}
function readU32(offset) {
  return isLE ? buf.readUInt32LE(offset) : buf.readUInt32BE(offset);
}
function readU64(offset) {
  // Read as BigInt then convert (for addresses/sizes)
  return isLE ? buf.readBigUInt64LE(offset) : buf.readBigUInt64BE(offset);
}

let e_phoff, e_phentsize, e_phnum;

if (is64) {
  e_phoff = Number(readU64(32));
  e_phentsize = readU16(54);
  e_phnum = readU16(56);
} else {
  e_phoff = readU32(28);
  e_phentsize = readU16(42);
  e_phnum = readU16(44);
}

const result = {};

// Parse program headers and extract LOAD segments
for (let i = 0; i < e_phnum; i++) {
  const phOff = e_phoff + i * e_phentsize;

  let p_type, p_offset, p_vaddr, p_filesz;

  if (is64) {
    p_type = readU32(phOff);
    p_offset = Number(readU64(phOff + 8));
    p_vaddr = Number(readU64(phOff + 16));
    p_filesz = Number(readU64(phOff + 32));
  } else {
    p_type = readU32(phOff);
    p_offset = readU32(phOff + 4);
    p_vaddr = readU32(phOff + 8);
    p_filesz = readU32(phOff + 16);
  }

  // PT_LOAD = 1
  if (p_type !== 1) continue;

  // Read 4-byte aligned values from this segment
  // Align start up to next 4-byte boundary
  const alignedStart = p_vaddr % 4 === 0 ? p_vaddr : p_vaddr + (4 - (p_vaddr % 4));

  for (let addr = alignedStart; addr + 4 <= p_vaddr + p_filesz; addr += 4) {
    const fileOff = p_offset + (addr - p_vaddr);
    if (fileOff + 4 <= buf.length) {
      const value = buf.readInt32LE(fileOff);
      result[addr.toString()] = value;
    }
  }
}

process.stdout.write(JSON.stringify(result) + '\n');

